// Comprehensive follower authenticity analysis
const profile = $input.first().json;
const requestData = $node['Influencer Profile Input'].json.body;

// Extract metrics based on platform
let followers, following, posts, engagement, profileAge;

if (requestData.platform === 'instagram') {
  followers = profile.followers_count || 0;
  following = profile.follows_count || 0;
  posts = profile.media_count || 0;
  const media = profile.media?.data || [];
  const totalEngagement = media.reduce((sum, post) => 
    sum + (post.like_count || 0) + (post.comments_count || 0), 0
  );
  engagement = media.length > 0 ? totalEngagement / media.length : 0;
  profileAge = Date.now() - new Date(profile.created_time || Date.now()).getTime();
} else if (requestData.platform === 'twitter') {
  const metrics = profile.data?.public_metrics || {};
  followers = metrics.followers_count || 0;
  following = metrics.following_count || 0;
  posts = metrics.tweet_count || 0;
  engagement = (metrics.like_count || 0) / Math.max(posts, 1);
  profileAge = Date.now() - new Date(profile.data?.created_at || Date.now()).getTime();
} else if (requestData.platform === 'tiktok') {
  const user = profile.userInfo?.user || {};
  followers = user.followerCount || 0;
  following = user.followingCount || 0;
  posts = user.videoCount || 0;
  engagement = (user.heart || 0) / Math.max(posts, 1);
  profileAge = Date.now();
}

// Calculate fraud indicators
const analysis = {
  // 1. Follower-to-Following Ratio (red flag if < 0.5 for influencers)
  followerRatio: following > 0 ? followers / following : followers,
  followerRatioScore: (() => {
    const ratio = following > 0 ? followers / following : followers / 1000;
    if (ratio > 10) return 100; // Excellent
    if (ratio > 5) return 85;
    if (ratio > 2) return 70;
    if (ratio > 1) return 50;
    if (ratio > 0.5) return 30;
    return 10; // Suspicious
  })(),

  // 2. Engagement Rate (industry average: 1-5%)
  engagementRate: followers > 0 ? (engagement / followers) * 100 : 0,
  engagementScore: (() => {
    const rate = followers > 0 ? (engagement / followers) * 100 : 0;
    if (rate > 10) return 100; // Excellent
    if (rate > 5) return 90;
    if (rate > 2) return 75;
    if (rate > 1) return 60;
    if (rate > 0.5) return 40;
    if (rate > 0.1) return 20;
    return 5; // Likely fake engagement
  })(),

  // 3. Content Consistency (posts per week)
  postsPerWeek: (posts / (profileAge / (7 * 24 * 60 * 60 * 1000))) || 0,
  consistencyScore: (() => {
    const postsWeek = (posts / Math.max(profileAge / (7 * 24 * 60 * 60 * 1000), 1)) || 0;
    if (postsWeek >= 3 && postsWeek <= 10) return 100; // Optimal
    if (postsWeek >= 1) return 80;
    if (postsWeek >= 0.5) return 60;
    return 30; // Inactive or spam
  })(),

  // 4. Account Age vs Follower Growth (suspicious if too fast)
  accountAgeMonths: profileAge / (30 * 24 * 60 * 60 * 1000),
  growthVelocity: followers / Math.max(profileAge / (30 * 24 * 60 * 60 * 1000), 1),
  growthScore: (() => {
    const months = Math.max(profileAge / (30 * 24 * 60 * 60 * 1000), 1);
    const velocity = followers / months;

    // Gradual growth is authentic
    if (velocity < 1000 && months > 6) return 100;
    if (velocity < 5000 && months > 3) return 85;
    if (velocity < 10000) return 70;
    if (velocity < 50000) return 50;
    return 20; // Suspicious rapid growth
  })(),

  // 5. Profile Completeness
  profileComplete: (() => {
    let score = 0;
    if (profile.description || profile.bio) score += 30;
    if (profile.profile_pic_url || profile.profile_image_url) score += 30;
    if (profile.website || profile.url) score += 20;
    if (profile.verified) score += 20;
    return score;
  })(),

  // 6. Follower Quality Indicators
  suspiciousFollowerIndicators: {
    highFollowingRatio: following / Math.max(followers, 1) > 2,
    lowEngagement: (engagement / Math.max(followers, 1)) * 100 < 0.5,
    rapidGrowth: (followers / Math.max(profileAge / (30 * 24 * 60 * 60 * 1000), 1)) > 50000,
    fewPosts: posts < 10 && followers > 10000,
    noVerification: !profile.verified && followers > 100000
  }
};

// Calculate red flags
const redFlags = [];
if (analysis.suspiciousFollowerIndicators.highFollowingRatio) {
  redFlags.push('High following-to-follower ratio suggests fake account or bot behavior');
}
if (analysis.suspiciousFollowerIndicators.lowEngagement) {
  redFlags.push('Extremely low engagement rate indicates purchased followers');
}
if (analysis.suspiciousFollowerIndicators.rapidGrowth) {
  redFlags.push('Unnaturally rapid follower growth detected');
}
if (analysis.suspiciousFollowerIndicators.fewPosts) {
  redFlags.push('Large follower count with minimal content suggests inauthenticity');
}
if (analysis.suspiciousFollowerIndicators.noVerification) {
  redFlags.push('No platform verification despite significant following');
}

// Overall fraud risk score (weighted average)
const fraudScore = Math.round(
  (analysis.followerRatioScore * 0.25) +
  (analysis.engagementScore * 0.35) +
  (analysis.consistencyScore * 0.15) +
  (analysis.growthScore * 0.15) +
  (analysis.profileComplete * 0.10)
);

// Risk classification
let riskLevel = 'UNKNOWN';
let recommendation = 'Insufficient data for analysis';

if (fraudScore >= 80) {
  riskLevel = 'LOW RISK';
  recommendation = 'APPROVED - Authentic influencer with genuine engagement';
} else if (fraudScore >= 60) {
  riskLevel = 'MEDIUM RISK';
  recommendation = 'REVIEW - Some concerns, conduct additional verification';
} else if (fraudScore >= 40) {
  riskLevel = 'HIGH RISK';
  recommendation = 'CAUTION - Multiple fraud indicators detected';
} else {
  riskLevel = 'CRITICAL RISK';
  recommendation = 'REJECTED - Strong evidence of fake followers and fraud';
}

return [{
  json: {
    influencer: {
      username: requestData.username,
      platform: requestData.platform,
      profileUrl: requestData.platform === 'instagram' 
        ? `https://instagram.com/${requestData.username}`
        : requestData.platform === 'twitter'
        ? `https://twitter.com/${requestData.username}`
        : `https://tiktok.com/@${requestData.username}`
    },
    metrics: {
      followers,
      following,
      posts,
      engagementPerPost: Math.round(engagement),
      accountAgeMonths: Math.round(analysis.accountAgeMonths),
      verified: profile.verified || false
    },
    analysis: {
      followerRatio: analysis.followerRatio.toFixed(2),
      engagementRate: analysis.engagementRate.toFixed(3) + '%',
      postsPerWeek: analysis.postsPerWeek.toFixed(1),
      growthVelocity: Math.round(analysis.growthVelocity) + ' followers/month'
    },
    scoring: {
      followerQuality: analysis.followerRatioScore,
      engagementQuality: analysis.engagementScore,
      contentConsistency: analysis.consistencyScore,
      growthPattern: analysis.growthScore,
      profileCompleteness: analysis.profileComplete
    },
    fraudAssessment: {
      overallScore: fraudScore,
      riskLevel,
      recommendation,
      redFlags,
      suspiciousIndicators: analysis.suspiciousFollowerIndicators
    },
    timestamp: new Date().toISOString(),
    rawData: profile
  }
}];

