// Generate comprehensive fraud detection report
const analysis = $node['Analyze Follower Patterns'].json;
const aiResponse = $input.first().json;

// Parse AI response
let aiAnalysis = {};
try {
  const aiContent = aiResponse.content?.[0]?.text || '{}';
  const jsonMatch = aiContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    aiAnalysis = JSON.parse(jsonMatch[0]);
  }
} catch (error) {
  aiAnalysis = {
    verdict: 'ERROR',
    indicators: ['AI analysis failed'],
    concerns: 'Unable to complete AI verification',
    recommendation: 'MANUAL REVIEW REQUIRED',
    confidence: 0,
    summary: 'Technical error during AI analysis'
  };
}

// Combined final score (70% automated + 30% AI)
const automatedScore = analysis.fraudAssessment.overallScore;
const aiConfidence = aiAnalysis.confidence || 50;
const finalScore = Math.round((automatedScore * 0.7) + (aiConfidence * 0.3));

// Determine final decision
let finalDecision = 'MANUAL REVIEW';
let partnershipRecommendation = 'HOLD';

if (finalScore >= 75 && aiAnalysis.recommendation?.includes('APPROVE')) {
  finalDecision = 'APPROVED FOR PARTNERSHIP';
  partnershipRecommendation = 'PROCEED';
} else if (finalScore < 45 || aiAnalysis.recommendation?.includes('REJECT')) {
  finalDecision = 'REJECTED - HIGH FRAUD RISK';
  partnershipRecommendation = 'DO NOT PROCEED';
} else {
  finalDecision = 'REQUIRES MANUAL REVIEW';
  partnershipRecommendation = 'ADDITIONAL VERIFICATION NEEDED';
}

// Generate report
const report = {
  reportId: `FRAUD-${Date.now()}-${Math.random().toString(36).substr(2, 6).toUpperCase()}`,
  generatedAt: new Date().toISOString(),

  influencerProfile: analysis.influencer,

  executiveSummary: {
    finalDecision,
    partnershipRecommendation,
    overallAuthenticityScore: finalScore,
    riskLevel: finalScore >= 75 ? 'LOW' : finalScore >= 60 ? 'MEDIUM' : finalScore >= 45 ? 'HIGH' : 'CRITICAL',
    aiVerdict: aiAnalysis.verdict || 'UNKNOWN',
    aiConfidence: aiConfidence + '%'
  },

  keyMetrics: analysis.metrics,

  detailedAnalysis: {
    followerAuthenticity: {
      score: analysis.scoring.followerQuality,
      ratio: analysis.analysis.followerRatio,
      assessment: analysis.scoring.followerQuality >= 70 ? 'Healthy follower ratio' : 'Suspicious ratio detected'
    },
    engagementQuality: {
      score: analysis.scoring.engagementQuality,
      rate: analysis.analysis.engagementRate,
      assessment: analysis.scoring.engagementQuality >= 60 ? 'Genuine engagement' : 'Low or fake engagement'
    },
    contentConsistency: {
      score: analysis.scoring.contentConsistency,
      frequency: analysis.analysis.postsPerWeek,
      assessment: analysis.scoring.contentConsistency >= 60 ? 'Regular posting pattern' : 'Irregular activity'
    },
    growthPattern: {
      score: analysis.scoring.growthPattern,
      velocity: analysis.analysis.growthVelocity,
      assessment: analysis.scoring.growthPattern >= 70 ? 'Organic growth' : 'Suspicious growth pattern'
    }
  },

  fraudIndicators: {
    automatedRedFlags: analysis.fraudAssessment.redFlags,
    aiConcerns: aiAnalysis.indicators || [],
    suspiciousPatterns: Object.keys(analysis.fraudAssessment.suspiciousIndicators)
      .filter(key => analysis.fraudAssessment.suspiciousIndicators[key])
      .map(key => key.replace(/([A-Z])/g, ' $1').trim())
  },

  aiInsights: {
    verdict: aiAnalysis.verdict,
    keyFindings: aiAnalysis.indicators || [],
    specificConcerns: aiAnalysis.concerns || 'None provided',
    summary: aiAnalysis.summary || 'AI analysis completed'
  },

  recommendations: {
    partnership: partnershipRecommendation,
    nextSteps: finalDecision.includes('APPROVED') ? [
      'Proceed with partnership negotiations',
      'Set clear deliverables and KPIs',
      'Monitor performance metrics closely',
      'Establish fraud detection checkpoints'
    ] : finalDecision.includes('REJECTED') ? [
      'Do not proceed with partnership',
      'Document fraud indicators for records',
      'Consider reporting to platform',
      'Review screening criteria'
    ] : [
      'Conduct manual profile review',
      'Request additional verification documents',
      'Analyze recent audience growth patterns',
      'Review competitor partnerships',
      'Consider trial campaign first'
    ],
    estimatedFakeFollowerPercentage: Math.max(0, Math.round(100 - finalScore)) + '%'
  },

  confidenceScore: {
    automated: automatedScore,
    aiVerification: aiConfidence,
    combined: finalScore,
    methodology: '70% algorithmic analysis + 30% AI behavioral analysis'
  }
};

console.log(`\n========== FRAUD DETECTION REPORT ==========`);
console.log(`Influencer: @${analysis.influencer.username}`);
console.log(`Platform: ${analysis.influencer.platform}`);
console.log(`Final Score: ${finalScore}/100`);
console.log(`Decision: ${finalDecision}`);
console.log(`==========================================\n`);

return [{ json: report }];
